const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1440, height: 1800 } });
  await page.goto('https://inmobiliariaiparralde.com/', { waitUntil: 'domcontentloaded' });
  await page.waitForTimeout(4000);

  const info = await page.evaluate(() => {
    const selects = [...document.querySelectorAll('select')].map(s => ({
      name: s.name,
      id: s.id,
      className: s.className,
      options: [...s.options].slice(0, 12).map(o => o.textContent.trim())
    }));
    const buttons = [...document.querySelectorAll('button, input[type="submit"], a, .btn')]
      .map(el => (el.textContent || el.value || '').trim())
      .filter(Boolean)
      .slice(0, 200);
    return { title: document.title, selects, buttons };
  });

  console.log(JSON.stringify(info, null, 2));
  await page.screenshot({ path: 'home.png', fullPage: true });
  await browser.close();
})();
'@ | Set-Content -Path .\probe.js; node .\probe.js

