const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1440, height: 1800 } });
  await page.goto('https://inmobiliariaiparralde.com/', { waitUntil: 'domcontentloaded' });
  await page.waitForTimeout(3000);

  const forms = await page.evaluate(() => {
    return [...document.querySelectorAll('form')].map((f, i) => ({
      index: i,
      id: f.id,
      className: f.className,
      action: f.getAttribute('action'),
      method: f.getAttribute('method'),
      selects: [...f.querySelectorAll('select')].map(s => ({ name: s.name, cls: s.className, first: [...s.options].slice(0,4).map(o => o.textContent.trim()) })),
      submits: [...f.querySelectorAll('button, input[type="submit"]')].map(b => ({ tag: b.tagName, type: b.type, txt: (b.textContent||b.value||'').trim(), cls: b.className }))
    }));
  });

  console.log(JSON.stringify(forms, null, 2));
  await browser.close();
})();
