const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1440, height: 2200 } });
  await page.goto('https://inmobiliariaiparralde.com/', { waitUntil: 'domcontentloaded' });
  await page.waitForTimeout(2000);

  const form = page.locator('form.findus').first();
  await form.locator('select[name="tipoInmueble[]"]').selectOption({ label: 'Piso' });
  await form.locator('select[name="municipio[]"]').selectOption({ label: 'Hendaye' });

  await Promise.all([
    page.waitForNavigation({ waitUntil: 'domcontentloaded' }),
    form.locator('button[type="submit"]').click()
  ]);

  await page.waitForTimeout(3000);

  const data = await page.evaluate(() => {
    const cards = [...document.querySelectorAll('article, .single-properties, .card-product, .single-product, .property-item, .single-product-item')];
    const cardSample = cards.slice(0, 5).map(c => {
      const a = c.querySelector('a[href*="/inmuebles/"]') || c.querySelector('a');
      const title = c.querySelector('h1,h2,h3,h4,.title,.entry-title,.titulo')?.textContent?.trim() || a?.textContent?.trim() || '';
      const price = [...c.querySelectorAll('*')].map(n => n.textContent?.trim() || '').find(t => /€/.test(t) && t.length < 30) || '';
      return {
        cls: c.className,
        title,
        price,
        href: a?.href || ''
      };
    });

    const pagination = [...document.querySelectorAll('.pagination a, .page-numbers a, ul.pagination li a')].map(a => ({
      t: a.textContent.trim(),
      href: a.href,
      cls: a.className
    }));

    const title = document.title;
    return { title, url: location.href, cardCount: cards.length, cardSample, pagination };
  });

  console.log(JSON.stringify(data, null, 2));
  await page.screenshot({ path: 'results_probe.png', fullPage: true });
  await browser.close();
})();
'@ | Set-Content -Path .\results_probe.js; node .\results_probe.js

