const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1366, height: 2200 } });
  await page.goto('https://inmobiliariaiparralde.com/', { waitUntil: 'domcontentloaded' });
  await page.waitForTimeout(2000);

  const form = page.locator('form.findus').first();
  await form.locator('select[name="tipoInmueble[]"]').selectOption('Piso');
  await form.locator('select[name="municipio[]"]').selectOption('Hendaye');
  await Promise.all([
    page.waitForNavigation({ waitUntil: 'domcontentloaded' }),
    form.locator('button[type="submit"]').click()
  ]);
  await page.waitForTimeout(2000);

  const sample = await page.evaluate(() => {
    const all = [...document.querySelectorAll('div')].filter(d => typeof d.className === 'string' && /property|listing|inmueble/i.test(d.className));
    const classCounts = {};
    for (const el of all) {
      classCounts[el.className] = (classCounts[el.className] || 0) + 1;
    }
    const sorted = Object.entries(classCounts).sort((a,b)=>b[1]-a[1]).slice(0,40);

    const cards = [...document.querySelectorAll('.property-list-list')].slice(0,3).map(card => ({
      className: card.className,
      text: card.textContent.replace(/\s+/g,' ').trim().slice(0,400),
      links: [...card.querySelectorAll('a[href]')].map(a => ({href: a.href, text: a.textContent.trim(), cls: a.className}))
    }));

    return { sorted, cardsCount: document.querySelectorAll('.property-list-list').length, cards };
  });

  console.log(JSON.stringify(sample, null, 2));
  await browser.close();
})();
